from urllib.parse import quote
def encode_query(params: Mapping[str, str | Sequence[str]]) -> str:
    if not isinstance(params, Mapping): raise ValueError('mapping required')
    if any(not isinstance(key, str) for key in params): raise ValueError('string key required')
    pairs = []
    for key in sorted(params):
        raw = params[key]
        if isinstance(raw, str): values = [raw]
        elif isinstance(raw, Sequence) and not isinstance(raw, (bytes, bytearray)): values = list(raw)
        else: raise ValueError('invalid query value')
        if any(not isinstance(value, str) for value in values): raise ValueError('string values required')
        pairs.extend((key, value) for value in values)
    return '&'.join(quote(key, safe='') + '=' + quote(value, safe='') for key, value in pairs)
